import scala.xml._
import scala.util.{Try, Success, Failure}
import java.io.StringReader
import javax.xml.parsers.SAXParserFactory
import org.xml.sax.InputSource

case class ConfigurationSettings(
  name: String,
  version: String,
  properties: Map[String, String],
  database: Option[DatabaseConfig],
  servers: List[ServerConfig],
  features: List[String]
)

case class DatabaseConfig(
  host: String,
  port: Int,
  database: String,
  username: String,
  password: String
)

case class ServerConfig(
  name: String,
  host: String,
  port: Int,
  enabled: Boolean
)

class ConfigurationParserService {
  
  private val maxEntityExpansions = 10
  private val maxXmlSize = 1048576 // 1MB
  
  def parseConfiguration(xmlString: String): Either[String, ConfigurationSettings] = {
    validateXmlSize(xmlString) match {
      case Left(error) => Left(error)
      case Right(_) =>
        parseXmlSafely(xmlString) match {
          case Success(xml) => extractSettings(xml)
          case Failure(exception) => Left(s"XML parsing error: ${exception.getMessage}")
        }
    }
  }
  
  private def validateXmlSize(xmlString: String): Either[String, Unit] = {
    if (xmlString.length > maxXmlSize) {
      Left(s"XML size exceeds maximum allowed size of $maxXmlSize bytes")
    } else {
      Right(())
    }
  }
  
  private def parseXmlSafely(xmlString: String): Try[Elem] = {
    Try {
      val factory = SAXParserFactory.newInstance()
      factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
      factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
      factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
      factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
      factory.setXIncludeAware(false)
      
      XML.withSAXParser(factory.newSAXParser()).loadString(xmlString)
    }
  }
  
  private def extractSettings(xml: Elem): Either[String, ConfigurationSettings] = {
    Try {
      val name = (xml \ "@name").text
      val version = (xml \ "@version").text
      
      if (name.isEmpty) {
        return Left("Configuration name is required")
      }
      
      val properties = extractProperties(xml \ "properties")
      val database = extractDatabase(xml \ "database")
      val servers = extractServers(xml \ "servers" \ "server")
      val features = extractFeatures(xml \ "features" \ "feature")
      
      ConfigurationSettings(
        name = name,
        version = if (version.isEmpty) "1.0" else version,
        properties = properties,
        database = database,
        servers = servers,
        features = features
      )
    } match {
      case Success(config) => Right(config)
      case Failure(exception) => Left(s"Configuration extraction error: ${exception.getMessage}")
    }
  }
  
  private def extractProperties(propertiesNode: NodeSeq): Map[String, String] = {
    val properties = (propertiesNode \ "property").map { prop =>
      val key = (prop \ "@key").text
      val value = (prop \ "@value").text
      key -> value
    }.toMap
    
    properties
  }
  
  private def extractDatabase(dbNode: NodeSeq): Option[DatabaseConfig] = {
    if (dbNode.isEmpty) {
      None
    } else {
      Some(DatabaseConfig(
        host = (dbNode \ "host").text,
        port = (dbNode \ "port").text.toIntOption.getOrElse(5432),
        database = (dbNode \ "database").text,
        username = (dbNode \ "username").text,
        password = (dbNode \ "password").text
      ))
    }
  }
  
  private def extractServers(serverNodes: NodeSeq): List[ServerConfig] = {
    serverNodes.map { server =>
      ServerConfig(
        name = (server \ "@name").text,
        host = (server \ "host").text,
        port = (server \ "port").text.toIntOption.getOrElse(8080),
        enabled = (server \ "enabled").text.toBooleanOption.getOrElse(true)
      )
    }.toList
  }
  
  private def extractFeatures(featureNodes: NodeSeq): List[String] = {
    featureNodes.map(_.text).filter(_.nonEmpty).toList
  }
  
  def parseConfigurationWithReferences(xmlString: String): Either[String, ConfigurationSettings] = {
    validateXmlSize(xmlString) match {
      case Left(error) => Left(error)
      case Right(_) =>
        parseXmlSafely(xmlString) match {
          case Success(xml) =>
            val resolvedXml = resolveReferences(xml)
            extractSettings(resolvedXml)
          case Failure(exception) => Left(s"XML parsing error: ${exception.getMessage}")
        }
    }
  }
  
  private def resolveReferences(xml: Elem): Elem = {
    val references = extractReferenceDefinitions(xml)
    substituteReferences(xml, references, 0)
  }
  
  private def extractReferenceDefinitions(xml: Elem): Map[String, String] = {
    val refsNode = xml \ "references" \ "ref"
    refsNode.map { ref =>
      val id = (ref \ "@id").text
      val value = (ref \ "@value").text
      id -> value
    }.toMap
  }
  
  private def substituteReferences(node: Node, references: Map[String, String], depth: Int): Elem = {
    if (depth > maxEntityExpansions) {
      throw new IllegalStateException("Maximum entity expansion depth exceeded")
    }
    
    node match {
      case elem: Elem =>
        val newAttributes = elem.attributes.map {
          case attr: Attribute =>
            val newValue = substituteInText(attr.value.text, references)
            new UnprefixedAttribute(attr.key, newValue, Null)
          case other => other
        }.foldLeft(Null: MetaData)((acc, attr) => attr.append(acc))
        
        val newChildren = elem.child.map {
          case e: Elem => substituteReferences(e, references, depth + 1)
          case Text(text) => Text(substituteInText(text, references))
          case other => other
        }
        
        elem.copy(attributes = newAttributes, child = newChildren)
      case other => 
        Elem(null, "root", Null, TopScope, false)
    }
  }
  
  private def substituteInText(text: String, references: Map[String, String]): String = {
    var result = text
    references.foreach { case (id, value) =>
      result = result.replace(s"&$id;", value)
      result = result.replace(s"$${$id}", value)
    }
    result
  }
  
  def validateConfiguration(config: ConfigurationSettings): List[String] = {
    var errors = List.empty[String]
    
    if (config.name.isEmpty) {
      errors = errors :+ "Configuration name cannot be empty"
    }
    
    config.database.foreach { db =>
      if (db.host.isEmpty) {
        errors = errors :+ "Database host cannot be empty"
      }
      if (db.port < 1 || db.port > 65535) {
        errors = errors :+ s"Database port ${db.port} is invalid"
      }
    }
    
    config.servers.zipWithIndex.foreach { case (server, idx) =>
      if (server.name.isEmpty) {
        errors = errors :+ s"Server at index $idx has empty name"
      }
      if (server.host.isEmpty) {
        errors = errors :+ s"Server ${server.name} has empty host"
      }
      if (server.port < 1 || server.port > 65535) {
        errors = errors :+ s"Server ${server.name} has invalid port ${server.port}"
      }
    }
    
    errors
  }
  
  def toXml(config: ConfigurationSettings): String = {
    val xml =
      <configuration name={config.name} version={config.version}>
        <properties>
          {config.properties.map { case (key, value) =>
            <property key={key} value={value}/>
          }}
        </properties>
        {config.database.map { db =>
          <database>
            <host>{db.host}</host>
            <port>{db.port}</port>
            <database>{db.database}</database>
            <username>{db.username}</username>
            <password>{db.password}</password>
          </database>
        }.getOrElse(NodeSeq.Empty)}
        <servers>
          {config.servers.map { server =>
            <server name={server.name}>
              <host>{server.host}</host>
              <port>{server.port}</port>
              <enabled>{server.enabled}</enabled>
            </server>
          }}
        </servers>
        <features>
          {config.features.map { feature =>
            <feature>{feature}</feature>
          }}
        </features>
      </configuration>
    
    xml.toString()
  }
}

